redis_client = Redis(host='localhost', port=6379, db=0)

# Set up session storage with Redis
@app.before_request
def load_session():
    session_id = request.cookies.get('session')
    if session_id:
        session_data = redis_client.get(f"session:{session_id}")
        if session_data:
            session.update(session.from_json(session_data.decode('utf-8')))

@app.after_request
def save_session(response):
    session_id = request.cookies.get('session') or str(int(time.time()))
    redis_client.set(f"session:{session_id}", session.to_json())
    response.set_cookie('session', session_id)
    return response

# Caching decorator
def cache(expiration=60):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = f"cache:{func.__name__}:{args}:{kwargs}"
            cached_result = redis_client.get(key)
            if cached_result:
                return jsonify({'data': cached_result.decode('utf-8'), 'cached': True})
            result = func(*args, **kwargs)
            redis_client.setex(key, expiration, result)
            return jsonify({'data': result, 'cached': False})
        return wrapper
    return decorator

